const a=[{id:"t001",year:1998,month:5,day:21,title:"Soeharto Mundur — Akhir Orde Baru",description:"Presiden Soeharto mengundurkan diri setelah 32 tahun berkuasa, menyusul gelombang demonstrasi mahasiswa dan krisis ekonomi 1997-1998. BJ Habibie dilantik sebagai Presiden ke-3 RI.",category:"politik",significance:10,person_ids:["prabowo"],tags:["reformasi","orde-baru","soeharto"],source:"Wikipedia"},{id:"t002",year:1998,month:5,day:12,title:"Tragedi Semanggi & Kerusuhan Mei 1998",description:"Kerusuhan rasial dan penembakan mahasiswa mengiringi kejatuhan Soeharto. Puluhan tewas. Laporan pelanggaran HAM berat hingga kini belum tuntas secara hukum.",category:"hukum",significance:9,person_ids:["prabowo"],tags:["ham","reformasi","kerusuhan"],source:"Kontras, Komnas HAM"},{id:"t003",year:1999,month:6,day:7,title:"Pemilu Legislatif Pertama Era Reformasi",description:"48 partai peserta Pemilu 1999. PDIP menang 33.7% suara. Gus Dur (PKB) terpilih Presiden melalui MPR, bukan suara terbanyak (Megawati).",category:"pemilu",significance:9,person_ids:["megawati"],tags:["pemilu","reformasi","pdip"],source:"KPU RI"},{id:"t004",year:1999,month:10,day:20,title:"Abdurrahman Wahid (Gus Dur) Terpilih Presiden ke-4",description:"MPR memilih Gus Dur mengalahkan Megawati yang partainya (PDIP) menang Pemilu. Awal dari koalisi 'Poros Tengah' partai-partai Islam.",category:"politik",significance:8,person_ids:["megawati"],tags:["gus-dur","poros-tengah","presiden"],source:"Wikipedia"},{id:"t005",year:2001,month:7,day:23,title:"Megawati Gantikan Gus Dur — Presiden ke-5",description:"MPR memberhentikan Gus Dur melalui Sidang Istimewa. Megawati Soekarnoputri dilantik sebagai Presiden ke-5, presiden perempuan pertama Indonesia.",category:"politik",significance:8,person_ids:["megawati"],tags:["megawati","presiden","pdip"],source:"Wikipedia"},{id:"t006",year:2002,month:10,day:12,title:"Bom Bali I — 202 Tewas",description:"Serangan bom teroris di Kuta, Bali. 202 orang tewas, mayoritas turis asing. Titik balik kebijakan anti-terorisme Indonesia. Densus 88 dibentuk.",category:"bencana",significance:9,person_ids:["megawati"],tags:["terorisme","bali","jemaah-islamiyah"],source:"Wikipedia"},{id:"t007",year:2004,month:9,day:20,title:"SBY Menang Pilpres Langsung Pertama",description:"Susilo Bambang Yudhoyono (Demokrat) mengalahkan Megawati 60.6% vs 39.4% dalam Pilpres langsung pertama Indonesia. Era Reformasi mengkonsolidasi demokrasi.",category:"pemilu",significance:9,person_ids:["sby","megawati"],tags:["sby","demokrat","pilpres","pertama"],source:"KPU RI"},{id:"t008",year:2004,month:12,day:26,title:"Tsunami Aceh — 230.000+ Tewas",description:"Gempa 9.1 SR dan tsunami menghancurkan pesisir Aceh dan Sumatera Utara. Lebih dari 230.000 jiwa meninggal. Terbesar dalam sejarah modern Indonesia.",category:"bencana",significance:10,person_ids:["sby"],tags:["tsunami","aceh","bencana-alam"],source:"BNPB"},{id:"t009",year:2005,month:8,day:15,title:"Perjanjian Damai Helsinki — Aceh",description:"MoU Helsinki antara Pemerintah RI dan GAM mengakhiri konflik bersenjata 29 tahun di Aceh. Disaksikan mantan Presiden Finlandia Martti Ahtisaari.",category:"politik",significance:9,person_ids:["muzakir_manaf"],tags:["aceh","gam","damai","helsinki"],source:"CMI / Wikipedia"},{id:"t010",year:2007,month:12,day:17,title:"KPK Pertama Kali Tuntut Anggota DPR",description:"KPK menahan Al Amin Nur Nasution (PPP), anggota DPR pertama yang ditangkap KPK. Menandai era baru pemberantasan korupsi.",category:"hukum",significance:7,person_ids:["sby"],tags:["kpk","korupsi","sejarah"],source:"KPK RI"},{id:"t011",year:2009,month:7,day:8,title:"SBY Menang Pilpres Periode 2 — Satu Putaran",description:"SBY-Boediono menang 60.8% dalam satu putaran, mengalahkan Mega-Prabowo dan JK-Wiranto. Kemenangan besar yang langka dalam demokrasi multipartai.",category:"pemilu",significance:8,person_ids:["sby","prabowo","megawati"],tags:["sby","pilpres","satu-putaran"],source:"KPU RI"},{id:"t012",year:2010,month:3,day:1,title:"Cicak vs Buaya I — KPK vs Polri",description:"Konflik terbuka antara KPK dan Polri saat KPK menyelidiki Kabareskrim Susno Duadji. Preseden berbahaya bagi independensi KPK.",category:"hukum",significance:8,person_ids:["sby"],tags:["kpk","polri","cicak-buaya"],source:"Tempo"},{id:"t013",year:2012,month:9,day:29,title:"Jokowi Menang Pilkada DKI Jakarta",description:"Joko Widodo dan Basuki Tjahaja Purnama (Ahok) mengalahkan Fauzi Bowo di putaran 2 Pilkada DKI. Awal kebangkitan Jokowi ke panggung nasional.",category:"pemilu",significance:8,person_ids:["jokowi"],tags:["jokowi","dki","pilkada","ahok"],source:"KPU DKI"},{id:"t014",year:2014,month:7,day:9,title:"Jokowi Menang Pilpres — Prabowo Kalah Pertama",description:"Joko Widodo mengalahkan Prabowo Subianto 53.15% vs 46.85%. Prabowo menolak hasil dan menarik diri dari proses KPU, tapi tidak menempuh jalur hukum.",category:"pemilu",significance:10,person_ids:["jokowi","prabowo"],tags:["jokowi","prabowo","pilpres","2014"],source:"KPU RI"},{id:"t015",year:2015,month:1,day:13,title:"Cicak vs Buaya II — Budi Gunawan vs KPK",description:"Jokowi nominasikan Budi Gunawan sebagai Kapolri. KPK menetapkannya tersangka sehari sebelum fit & proper test. Budi Gunawan kemudian bebas, KPK dikriminalisasi balik.",category:"hukum",significance:8,person_ids:["budi_gunawan"],tags:["kpk","polri","budi-gunawan","cicak-buaya"],source:"Tempo, KPK"},{id:"t016",year:2016,month:12,day:2,title:"Aksi 212 — Protes Ahok & Kasus Penistaan Agama",description:"Jutaan orang demo di Jakarta menuntut penuntutan Basuki Tjahaja Purnama (Ahok) atas dugaan penistaan agama. Salah satu demonstrasi terbesar dalam sejarah Indonesia.",category:"politik",significance:9,person_ids:["jokowi"],tags:["ahok","212","penistaan-agama","islam"],source:"Wikipedia"},{id:"t017",year:2019,month:4,day:17,title:"Jokowi Menang Pilpres — Prabowo Kalah Kedua",description:"Joko Widodo-Ma'ruf Amin mengalahkan Prabowo-Sandiaga Uno 55.5% vs 44.5%. Prabowo kembali menolak hasil, sempat umumkan 'kemenangan sepihak'. Ricuh 22 Mei 2019.",category:"pemilu",significance:10,person_ids:["jokowi","prabowo"],tags:["pilpres","2019","prabowo","jokowi"],source:"KPU RI"},{id:"t018",year:2019,month:9,day:17,title:"Revisi UU KPK — Pelemahan KPK",description:"DPR dan Pemerintah mengesahkan revisi UU KPK yang kontroversial dalam 12 hari. KPK kehilangan independensi: penyidik harus jadi ASN, ada Dewan Pengawas.",category:"hukum",significance:9,person_ids:["jokowi","puan","nawawi"],tags:["kpk","revisi","pelemahan","korupsi"],source:"ICW, Transparency International"},{id:"t019",year:2020,month:3,day:2,title:"COVID-19 Masuk Indonesia",description:"Kasus pertama COVID-19 dikonfirmasi di Indonesia. Jokowi awalnya meremehkan. Akhirnya lebih dari 160.000 meninggal resmi (actual diperkirakan jauh lebih tinggi).",category:"bencana",significance:9,person_ids:["jokowi"],tags:["covid","pandemi","kesehatan"],source:"Kemenkes RI"},{id:"t020",year:2022,month:1,day:18,title:"UU IKN Disahkan — Ibu Kota Pindah ke Kaltim",description:"DPR mengesahkan UU IKN. Ibu kota baru 'Nusantara' di Penajam Paser Utara, Kalimantan Timur. Proyek senilai Rp 466 triliun yang kontroversial.",category:"ekonomi",significance:9,person_ids:["jokowi"],tags:["ikn","nusantara","ibu-kota","kaltim"],source:"DPR RI, OIKN"},{id:"t021",year:2022,month:10,day:1,title:"Tragedi Kanjuruhan — 135 Tewas",description:"135 suporter Arema FC meninggal di Stadion Kanjuruhan, Malang, setelah polisi menembakkan gas air mata ke tribun. Tragedi olahraga terburuk Indonesia.",category:"bencana",significance:8,person_ids:["jokowi","listyo_sigit"],tags:["kanjuruhan","malang","tragedi","polri"],source:"TGIPF, Wikipedia"},{id:"t022",year:2023,month:10,day:16,title:"Putusan MK 90 — Gibran Bisa Maju Cawapres",description:"Mahkamah Konstitusi memutuskan pengecualian batas usia Capres-Cawapres bagi yang pernah menjabat kepala daerah. Putusan ini memungkinkan Gibran Rakabuming maju sebagai Cawapres Prabowo.",category:"hukum",significance:10,person_ids:["anwar_usman","gibran","jokowi"],tags:["mk","gibran","anwar-usman","kontroversial"],source:"MK RI"},{id:"t023",year:2023,month:11,day:7,title:"Anwar Usman Dicopot sebagai Ketua MK",description:"MKMK menjatuhkan sanksi berat: Anwar Usman dicopot dari jabatan Ketua MK karena pelanggaran etik berat dalam memutus perkara batas usia (yang menguntungkan Gibran — keponakan istrinya).",category:"hukum",significance:9,person_ids:["anwar_usman","suhartoyo","gibran"],tags:["mkmk","anwar-usman","etik","mk"],source:"MKMK RI"},{id:"t024",year:2024,month:2,day:14,title:"Pilpres 2024 — Prabowo-Gibran Menang Satu Putaran",description:"Prabowo Subianto-Gibran Rakabuming Raka menang 58.59%, mengalahkan Anies-Cak Imin (24.95%) dan Ganjar-Mahfud (16.47%). Pertama kali Prabowo menang setelah tiga kali gagal.",category:"pemilu",significance:10,person_ids:["prabowo","gibran","anies","ganjar","mahfud_md"],tags:["pilpres","2024","prabowo","menang"],source:"KPU RI"},{id:"t025",year:2024,month:2,day:29,title:"OTT KPK — Bupati Sidoarjo Ahmad Muhdlor",description:"KPK OTT Bupati Sidoarjo Ahmad Muhdlor Ali dalam kasus pemotongan insentif ASN BPBD senilai Rp 2.7 miliar. OTT pertama di tahun 2024.",category:"hukum",significance:7,person_ids:["gus_muhdlor","nawawi"],tags:["kpk","ott","sidoarjo","jatim"],source:"KPK RI"},{id:"t026",year:2024,month:10,day:20,title:"Prabowo Subianto Dilantik Presiden RI ke-8",description:"Prabowo Subianto dan Gibran Rakabuming Raka dilantik sebagai Presiden dan Wakil Presiden RI ke-8 dan ke-6. Kabinet Merah Putih dengan 48 menteri diumumkan.",category:"politik",significance:10,person_ids:["prabowo","gibran"],tags:["pelantikan","presiden","kabinet-merah-putih"],source:"Sekretariat Negara RI"},{id:"t027",year:2024,month:11,day:1,title:"Tom Lembong Ditangkap Kejaksaan Agung",description:"Thomas Lembong, mantan Mendag dan co-captain Tim Anies 2024, ditangkap Kejagung atas dugaan korupsi minyak goreng 2021-2022. Memicu perdebatan: penegakan hukum atau kriminalisasi oposan?",category:"hukum",significance:8,person_ids:["tom_lembong","anies","jokowi"],tags:["tom-lembong","kejagung","kriminalisasi","oposisi"],source:"Kejagung RI"},{id:"t028",year:2024,month:11,day:27,title:"Pilkada Serentak 2024 — Gerindra Dominasi",description:"Pilkada serentak di 37 provinsi + 508 kabupaten/kota. Gerindra/KIM Plus menang di mayoritas provinsi strategis: Jabar (Dedi Mulyadi), Jateng (Ahmad Luthfi), Sumut (Bobby), Banten, dll.",category:"pemilu",significance:9,person_ids:["prabowo","dedi_mulyadi","ahmad_luthfi","bobby_nasution"],tags:["pilkada","2024","gerindra","kim-plus"],source:"KPU RI"},{id:"t029",year:2025,month:1,day:8,title:"Hasto Kristiyanto Tersangka KPK",description:"Sekjen PDIP Hasto Kristiyanto ditetapkan KPK sebagai tersangka obstruction of justice dalam kasus Harun Masiku yang buron sejak 2020. PDIP menilai ini kriminalisasi oposisi.",category:"hukum",significance:8,person_ids:["hasto","megawati","puan","nawawi"],tags:["hasto","kpk","pdip","harun-masiku"],source:"KPK RI"},{id:"t030",year:2025,month:1,day:6,title:"Makan Bergizi Gratis Mulai Diluncurkan",description:"Program unggulan Prabowo — makan bergizi gratis — mulai diluncurkan di 26 provinsi pada Januari 2025. Anggaran Rp 71 triliun untuk 82 juta penerima manfaat.",category:"ekonomi",significance:7,person_ids:["prabowo","gibran"],tags:["mbg","makan-gratis","prabowo","program"],source:"Setkab RI"},{id:"t031",year:1965,month:9,day:30,title:"G30S/PKI — Titik Balik Soeharto",description:"Gerakan 30 September menandai berakhirnya era Soekarno dan awal Orde Baru Soeharto. Pembantaian massal PKI 1965-1966 diperkirakan 500.000–1 juta jiwa. Masih jadi luka sejarah yang belum tuntas.",category:"politik",significance:10,person_ids:["soekarno"],tags:["g30s","pki","soeharto","sejarah"],source:"Wikipedia/Kontras"},{id:"t032",year:1966,month:3,day:11,title:"Supersemar — Soeharto Ambil Alih Kekuasaan",description:"Surat Perintah Sebelas Maret memberi Soeharto kewenangan dari Soekarno. Isi asli dokumen masih diperdebatkan. Awal 32 tahun Orde Baru.",category:"politik",significance:9,person_ids:["soekarno"],tags:["supersemar","soeharto","orde-baru"],source:"Arsip Nasional"},{id:"t033",year:2006,month:5,day:27,title:"Gempa Yogyakarta — 5.800+ Tewas",description:"Gempa 6.3 SR mengguncang Bantul-Yogyakarta. Lebih dari 5.800 jiwa meninggal. Candi Prambanan rusak. Respons pemerintah dinilai lambat.",category:"bencana",significance:8,person_ids:["sby","sultan_hb10"],tags:["gempa","yogyakarta","bencana"],source:"BNPB"},{id:"t034",year:2008,month:1,day:1,title:"KPK Tangkap Pejabat Tinggi — Era Baru Pemberantasan Korupsi",description:"KPK mulai menangkap pejabat tinggi secara sistematis. Indeks persepsi korupsi Indonesia membaik dari 2.2 (2004) ke 2.8 (2008) — masih sangat rendah.",category:"hukum",significance:7,person_ids:["sby"],tags:["kpk","korupsi","reformasi-hukum"],source:"KPK RI"},{id:"t035",year:2008,month:10,day:1,title:"Krisis Finansial Global Hantam Indonesia",description:"Krisis subprime AS 2008 menekan rupiah ke Rp 12.000/USD. Sri Mulyani kelola APBN dengan defisit terkendali. Indonesia salah satu dari sedikit negara yang tetap tumbuh positif.",category:"ekonomi",significance:8,person_ids:["sri_mulyani"],tags:["krisis","ekonomi","rupiah"],source:"BI, BPS"},{id:"t036",year:2011,month:2,day:1,title:"Sri Mulyani Mundur ke World Bank — Akibat Kasus Century",description:"Kasus Bank Century (bail-out Rp 6.7 triliun) memaksa Sri Mulyani meninggalkan posisi Menkeu. DPR menekan pemerintah; Boediono-Sri Mulyani dinyatakan bersalah secara politik.",category:"hukum",significance:8,person_ids:["sri_mulyani","sby"],tags:["century","sri-mulyani","bank","korupsi"],source:"Wikipedia"},{id:"t037",year:2015,month:10,day:1,title:"Kebakaran Hutan Kalimantan-Sumatera Terburuk",description:"Kebakaran hutan dan lahan gambut 2015 menghasilkan kabut asap yang menutupi seluruh Sumatera dan Kalimantan. Kerugian Rp 221 triliun; 500.000+ ISPA; 24 jiwa meninggal langsung.",category:"bencana",significance:8,person_ids:["jokowi"],tags:["kebakaran-hutan","asap","gambut","kalimantan"],source:"BNPB, World Bank"},{id:"t038",year:2016,month:4,day:1,title:"Panama Papers — Nama Indonesia Muncul",description:"Bocoran dokumen Panama Papers menyeret nama-nama pejabat dan pengusaha Indonesia yang memiliki entitas di tax haven. KPK investigasi namun tidak ada penuntutan signifikan.",category:"hukum",significance:7,person_ids:["jokowi"],tags:["panama-papers","pajak","tax-haven"],source:"ICIJ"},{id:"t039",year:2017,month:4,day:25,title:"Ahok Divonis 2 Tahun Penjara",description:"Basuki Tjahaja Purnama (Ahok) divonis 2 tahun penjara atas kasus penistaan agama. Vonis lebih berat dari tuntutan jaksa (1 tahun). Memperlihatkan tekanan politik dan agama terhadap pengadilan.",category:"hukum",significance:9,person_ids:["jokowi","anies"],tags:["ahok","penistaan-agama","vonis","dki"],source:"PN Jakarta Utara"},{id:"t040",year:2018,month:8,day:1,title:"Asian Games 2018 — Jakarta-Palembang",description:"Indonesia sukses menjadi tuan rumah Asian Games ke-18. Pembangunan GBK renovasi, infrastruktur Jakarta dipercepat. Indonesia raih posisi ke-4 dengan 98 medali.",category:"internasional",significance:7,person_ids:["jokowi"],tags:["asian-games","olahraga","jakarta"],source:"KOI"},{id:"t041",year:2019,month:5,day:22,title:"Kerusuhan 22 Mei — Pasca Pilpres 2019",description:"Kerusuhan pasca pengumuman hasil Pilpres 2019. 8 orang tewas, ratusan luka. Diduga ada provokasi terstruktur. Beberapa aktivis ditangkap dengan tuduhan makar.",category:"politik",significance:8,person_ids:["prabowo","jokowi"],tags:["kerusuhan","pilpres","makar","2019"],source:"Komnas HAM"},{id:"t042",year:2019,month:9,day:23,title:"RKUHP & RUU KPK — Mahasiswa Demo Besar",description:"Gelombang demo mahasiswa besar-besaran ('Indonesia Gelap') menolak revisi KUHP dan pelemahan KPK. Beberapa mahasiswa tewas di Kendari. Jokowi akhirnya tunda RKUHP.",category:"politik",significance:8,person_ids:["jokowi"],tags:["mahasiswa","demo","kpk","rkuhp"],source:"Wikipedia"},{id:"t043",year:2020,month:10,day:5,title:"UU Cipta Kerja (Omnibus Law) Disahkan — Kontroversial",description:"DPR mengesahkan UU Cipta Kerja dalam tempo kilat di tengah pandemi. Buruh, mahasiswa, dan akademisi protes keras. MK sempat menyatakan inkonstitusional bersyarat 2021.",category:"ekonomi",significance:9,person_ids:["jokowi","airlangga"],tags:["omnibus","cipta-kerja","buruh","kontroversi"],source:"DPR RI"},{id:"t044",year:2021,month:1,day:13,title:"Vaksinasi COVID-19 Pertama — Jokowi Divaksin Live",description:"Presiden Jokowi menjadi orang pertama yang divaksin COVID-19 di Indonesia secara live TV. Program vaksinasi nasional dimulai dengan target 181 juta orang.",category:"bencana",significance:8,person_ids:["jokowi"],tags:["covid","vaksin","pandemi"],source:"Kemenkes RI"},{id:"t045",year:2021,month:4,day:21,title:"KRI Nanggala-402 Tenggelam — 53 Awak Gugur",description:"Kapal selam TNI AL KRI Nanggala-402 hilang kontak di perairan Bali, ditemukan hancur di kedalaman 838 meter. 53 prajurit gugur. Tragedi militer terburuk era modern.",category:"militer",significance:8,person_ids:["jokowi","agus_subiyanto"],tags:["tni","kapal-selam","nanggala","militer"],source:"Kemenhan RI"},{id:"t046",year:2022,month:9,day:3,title:"BBM Naik Drastis — Pertamax, Pertalite Melonjak",description:"Pemerintah Jokowi menaikkan harga BBM bersubsidi: Pertalite naik 30%, Solar naik 32%. Alasan: subsidi membengkak Rp 502 triliun. Protes di berbagai kota.",category:"ekonomi",significance:7,person_ids:["jokowi","sri_mulyani"],tags:["bbm","subsidi","inflasi","protes"],source:"Pertamina, ESDM"},{id:"t047",year:2024,month:2,day:15,title:"Pileg 2024 — KIM Plus Kuasai DPR, PDIP Terisolasi",description:"Gerindra tetap kuat (13.2%) bersama Golkar (15.28%). KIM Plus gabungan menguasai mayoritas kursi DPR. PDIP menjadi satu-satunya kekuatan oposisi riil.",category:"pemilu",significance:8,person_ids:["prabowo","sufmi_dasco"],tags:["pileg","gerindra","kim-plus"],source:"KPU RI"},{id:"t048",year:2024,month:8,day:22,title:"Demo Darurat Indonesia — Mahasiswa Tolak RUU Pilkada",description:"Jutaan mahasiswa dan masyarakat demo nasional menolak RUU Pilkada yang dianggap mengkhianati putusan MK soal syarat pencalonan. Jokowi akhirnya mundur. Anies-Sohibul diloloskan MK.",category:"politik",significance:9,person_ids:["jokowi","puan","gibran"],tags:["demo","mahasiswa","pilkada","ruu"],source:"Wikipedia"},{id:"t049",year:2024,month:10,day:21,title:"Kabinet Merah Putih — 48 Menteri Terbanyak",description:"Prabowo lantik Kabinet Merah Putih dengan 48 menteri — terbanyak dalam sejarah RI. Termasuk beberapa Wakil Menteri per kementerian. Dikritik sebagai bagi-bagi kue koalisi.",category:"politik",significance:8,person_ids:["prabowo","gibran","sri_mulyani","airlangga","ahy"],tags:["kabinet","merah-putih","menteri"],source:"Sekretariat Negara"},{id:"t050",year:2025,month:2,day:4,title:"Efisiensi Anggaran Prabowo — Potong Rp 306 Triliun",description:"Prabowo memotong anggaran kementerian/lembaga Rp 306 triliun untuk efisiensi. Termasuk anggaran perjalanan dinas, rapat, dan infrastruktur non-prioritas. Kritik: potong pendidikan dan kesehatan.",category:"ekonomi",significance:8,person_ids:["prabowo","sri_mulyani"],tags:["efisiensi","anggaran","prabowo"],source:"Kemenkeu RI"},{id:"t051",year:2025,month:2,day:24,title:"Danantara — Sovereign Wealth Fund Prabowo Diluncurkan",description:"Badan Pengelola Investasi Daya Anagata Nusantara (Danantara) diluncurkan Prabowo. Mengelola aset BUMN Rp 9.000 triliun. Dipimpin Rosan Roeslani. Dikritik soal transparansi dan tata kelola.",category:"ekonomi",significance:9,person_ids:["prabowo","erick_thohir"],tags:["danantara","bumn","investasi","sovereign-wealth"],source:"Keppres RI"},{id:"t052",year:2005,month:10,day:1,title:"Bom Bali II — 20 Tewas",description:"Bom bunuh diri meledak di Jimbaran dan Kuta, Bali. 20 orang tewas, 100+ luka. Serangan kedua Jemaah Islamiyah di Bali. Densus 88 berhasil ungkap jaringan pelaku.",category:"bencana",significance:8,person_ids:["sby"],tags:["terorisme","bali","bom","jemaah-islamiyah"],source:"Wikipedia, Polri"},{id:"t053",year:2006,month:5,day:29,title:"Lumpur Lapindo — Bencana Industri Terbesar RI",description:"Semburan lumpur panas dari pengeboran PT Lapindo Brantas di Porong, Sidoarjo. Rendam 12 desa, 39.000 warga mengungsi. Kontroversi: bencana alam atau kelalaian korporasi? Aburizal Bakrie pemilik Lapindo.",category:"bencana",significance:9,person_ids:["sby"],tags:["lapindo","lumpur","sidoarjo","bencana-industri"],source:"BPLS, Wikipedia"},{id:"t054",year:2017,month:4,day:19,title:"Pilkada DKI 2017 — Ahok Kalah, Anies Menang",description:"Anies Baswedan-Sandiaga Uno mengalahkan Ahok (Basuki-Djarot) di putaran 2 Pilkada DKI 57.96% vs 42.04%. Ahok kalah setelah demo 212 dan kasus penistaan agama. Titik balik politik identitas Indonesia.",category:"pemilu",significance:9,person_ids:["anies","jokowi"],tags:["pilkada","dki","ahok","anies","212"],source:"KPU DKI"},{id:"t055",year:2022,month:12,day:6,title:"KUHP Baru Disahkan — Pasal Kontroversial",description:"DPR mengesahkan KUHP baru setelah 59 tahun. Sejumlah pasal kontroversial: pidana kumpul kebo, hukuman bagi penghinaan presiden, dan pidana perzinaan. Berlaku setelah 3 tahun (2025).",category:"hukum",significance:8,person_ids:["jokowi","puan"],tags:["kuhp","hukum","pidana","kontroversi"],source:"DPR RI"},{id:"t056",year:2023,month:3,day:29,title:"Piala Dunia U-20 Batal di Indonesia — Isu Israel",description:"FIFA mencabut status tuan rumah Indonesia untuk Piala Dunia U-20 2023 setelah penolakan sejumlah kepala daerah (Gubernur Bali Koster, Gubernur Jateng Ganjar) terhadap kehadiran timnas Israel. Kerugian reputasi dan ekonomi.",category:"internasional",significance:8,person_ids:["ganjar","koster","jokowi"],tags:["piala-dunia","u20","israel","fifa","sepakbola"],source:"FIFA, PSSI"},{id:"t057",year:2020,month:1,day:8,title:"Harun Masiku Buron — DPO Terpanjang KPK",description:"Caleg PDIP Harun Masiku melarikan diri setelah KPK OTT kasus suap PAW DPR Rp 600 juta. Masih buron hingga 2025 — lebih dari 5 tahun. Diduga ada pelindung kuat. Hasto (Sekjen PDIP) jadi tersangka terkait.",category:"hukum",significance:8,person_ids:["hasto","nawawi","megawati"],tags:["harun-masiku","buron","kpk","pdip","dpo"],source:"KPK RI"},{id:"t058",year:1999,month:8,day:30,title:"Referendum Timor Timur — 78.5% Pilih Merdeka",description:"PBB menggelar referendum di Timor Timur. 78.5% memilih merdeka dari Indonesia. Milisi pro-Indonesia yang didukung TNI melakukan kekerasan pasca-referendum. Timor Leste resmi merdeka 2002.",category:"politik",significance:9,person_ids:["prabowo"],tags:["timtim","timor-leste","referendum","merdeka"],source:"PBB, Wikipedia"},{id:"t059",year:2003,month:12,day:27,title:"KPK Resmi Beroperasi",description:"Komisi Pemberantasan Korupsi (KPK) mulai beroperasi pada era SBY. Dibentuk berdasarkan UU No. 30/2002. Menjadi lembaga anti-korupsi terkuat dan paling ditakuti pejabat korup.",category:"hukum",significance:9,person_ids:["sby"],tags:["kpk","anti-korupsi","reformasi-hukum"],source:"KPK RI"},{id:"t060",year:2013,month:10,day:2,title:"Akil Mochtar Ditangkap KPK — Ketua MK Kena OTT",description:"Ketua Mahkamah Konstitusi Akil Mochtar ditangkap KPK secara OTT karena menerima suap sengketa Pilkada. Pukulan terberat terhadap kepercayaan lembaga peradilan Indonesia. Dihukum penjara seumur hidup.",category:"hukum",significance:9,person_ids:["sby","nawawi"],tags:["akil-mochtar","mk","kpk","ott","korupsi"],source:"KPK RI"},{id:"t061",year:2023,month:10,day:16,title:"Putusan MK No. 90/2023 — Gibran Boleh Maju Cawapres",description:"Mahkamah Konstitusi mengeluarkan putusan kontroversial: calon wakil presiden boleh berusia di bawah 40 tahun asal pernah/sedang menjabat kepala daerah terpilih. Putusan ini membuka jalan Gibran Rakabuming Raka (36 tahun) menjadi cawapres Prabowo.",category:"hukum",significance:10,person_ids:["prabowo","gibran","anwar_usman"],tags:["mk","putusan-mk","gibran","cawapres","kontroversial","anwar-usman"],source:"Mahkamah Konstitusi RI, 16 Oktober 2023"},{id:"t062",year:2023,month:10,day:19,title:"Pendaftaran Prabowo-Gibran ke KPU",description:"Prabowo Subianto dan Gibran Rakabuming Raka mendaftarkan diri sebagai pasangan capres-cawapres ke KPU. Koalisi Indonesia Maju (Gerindra, Golkar, PKB, Demokrat, dll.) resmi mengusung paslon nomor 2. Memicu kontroversi soal nepotisme Jokowi.",category:"pemilu",significance:9,person_ids:["prabowo","gibran","jokowi"],tags:["pilpres-2024","pendaftaran","kpu","koalisi-indonesia-maju"],source:"KPU RI, Oktober 2023"},{id:"t063",year:2023,month:11,day:7,title:"Anwar Usman Dicopot dari Jabatan Ketua MK",description:"Majelis Kehormatan MK (MKMK) menjatuhkan sanksi kepada Anwar Usman: dicopot dari jabatan Ketua MK karena pelanggaran etik berat dalam putusan usia cawapres. Anwar Usman adalah paman Gibran — konflik kepentingan terbukti.",category:"hukum",significance:9,person_ids:["anwar_usman","gibran"],tags:["mkmk","anwar-usman","etik","mk","pencopotan"],source:"MKMK RI, 7 November 2023"},{id:"t064",year:2023,month:10,day:10,title:"Syahrul Yasin Limpo Mundur dan Ditahan KPK",description:"Menteri Pertanian Syahrul Yasin Limpo mengundurkan diri dari kabinet Jokowi, kemudian ditangkap KPK atas kasus korupsi dan pemerasan di Kementan. Pertama kali menteri aktif era Jokowi ditangkap KPK.",category:"hukum",significance:8,person_ids:["jokowi","nawawi"],tags:["syl","kpk","korupsi","mentan","tangkap"],source:"KPK RI, Oktober 2023"},{id:"t065",year:2023,month:11,day:22,title:"Firli Bahuri Ditetapkan Tersangka — Ketua KPK Jadi Pesakitan",description:"Polda Metro Jaya menetapkan Firli Bahuri, Ketua KPK aktif, sebagai tersangka pemerasan terhadap Mentan SYL. Pertama kali dalam sejarah kepala lembaga anti-korupsi menjadi tersangka korupsi. Firli mengundurkan diri dari KPK.",category:"hukum",significance:10,person_ids:["nawawi"],tags:["firli-bahuri","kpk","tersangka","pemerasan","bersejarah"],source:"Polda Metro Jaya, 22 November 2023"},{id:"t066",year:2024,month:2,day:14,title:"Prabowo-Gibran Menang Pilpres Satu Putaran",description:"Pilpres 2024: Prabowo-Gibran meraih 58,6% suara, mengalahkan Anies-Muhaimin (24,9%) dan Ganjar-Mahfud (16,5%). Kemenangan satu putaran pertama sejak era pilpres langsung. Gugatan sengketa ke MK ditolak.",category:"pemilu",significance:10,person_ids:["prabowo","gibran","anies","ganjar"],tags:["pilpres-2024","menang","satu-putaran","kpu"],source:"KPU RI, 14 Februari 2024"},{id:"t067",year:2024,month:3,day:27,title:"Harvey Moeis Ditahan — Kasus Timah Rp271 Triliun",description:"Kejaksaan Agung menahan Harvey Moeis dalam kasus korupsi tata niaga timah PT Timah Tbk. Kerugian negara Rp 271 triliun menjadikannya kasus korupsi terbesar dalam sejarah Indonesia. Harvey Moeis adalah suami artis Sandra Dewi.",category:"hukum",significance:9,person_ids:[],tags:["harvey-moeis","timah","korupsi","terbesar","kejagung"],source:"Kejaksaan Agung RI, 27 Maret 2024"},{id:"t068",year:2024,month:10,day:20,title:"Prabowo Subianto Dilantik sebagai Presiden ke-8 RI",description:"Prabowo Subianto dilantik sebagai Presiden ke-8 Republik Indonesia oleh MPR. Gibran Rakabuming Raka dilantik sebagai Wakil Presiden. Pelantikan menandai berakhirnya era 10 tahun Jokowi dan dimulainya pemerintahan baru.",category:"politik",significance:10,person_ids:["prabowo","gibran","jokowi"],tags:["pelantikan","presiden","prabowo","gibran","mpr"],source:"MPR RI, 20 Oktober 2024"},{id:"t069",year:2024,month:11,day:1,title:"Tom Lembong Ditahan Kejaksaan Agung",description:"Thomas Trikasih Lembong (Tom Lembong), mantan Mendag dan co-captain Tim Anies 2024, ditahan Kejaksaan Agung atas kasus korupsi impor gula. Penahanan ini menuai tuduhan kriminalisasi oposisi karena dilakukan tak lama setelah Prabowo dilantik.",category:"hukum",significance:8,person_ids:["tom_lembong","prabowo"],tags:["tom-lembong","kejagung","korupsi","kriminalisasi","anies"],source:"Kejaksaan Agung RI, November 2024"},{id:"t070",year:2024,month:11,day:27,title:"Pilkada Serentak 2024 — Terbesar dalam Sejarah",description:"Pilkada serentak di 545 daerah seluruh Indonesia: 37 provinsi, 415 kabupaten, 93 kota. Khofifah-Emil menang di Jawa Timur, Ridwan Kamil kalah di Jakarta. Pramono Anung-Rano Karno memenangkan Jakarta mengalahkan kandidat Prabowo-Golkar.",category:"pemilu",significance:9,person_ids:["khofifah","prabowo"],tags:["pilkada-2024","serentak","jakarta","jatim","demokrasi"],source:"KPU RI, 27 November 2024"},{id:"t071",year:2025,month:1,day:8,title:"Hasto Kristiyanto Ditetapkan Tersangka KPK",description:"KPK menetapkan Hasto Kristiyanto, Sekjen DPP PDIP, sebagai tersangka dalam kasus obstruction of justice penyidikan Harun Masiku. Hasto diduga menghalangi penyidikan dan memerintahkan penghancuran barang bukti. Pukulan keras bagi PDIP sebagai oposisi.",category:"hukum",significance:9,person_ids:["hasto","megawati","nawawi"],tags:["hasto","kpk","tersangka","harun-masiku","pdip","obstruction"],source:"KPK RI, 8 Januari 2025"},{id:"t072",year:2025,month:2,day:24,title:"Danantara Resmi Diluncurkan",description:"Presiden Prabowo resmi meluncurkan Badan Pengelola Investasi Daya Anagata Nusantara (Danantara). Lembaga ini mengelola aset BUMN senilai Rp 9.000 triliun — menjadikannya salah satu sovereign wealth fund terbesar di Asia. Rosan Roeslani sebagai CEO.",category:"ekonomi",significance:9,person_ids:["prabowo","erick_thohir"],tags:["danantara","swf","bumn","investasi","rosan"],source:"Kantor Presiden RI, 24 Februari 2025"},{id:"t073",year:2025,month:2,day:20,title:"Pelantikan Serentak 481 Kepala Daerah Hasil Pilkada 2024",description:"Presiden Prabowo melantik 481 kepala daerah terpilih hasil Pilkada 2024 secara serentak di Istana Negara. Termasuk 37 pasang gubernur-wagub dari 37 provinsi. Pelantikan massal terbesar dalam sejarah demokrasi lokal Indonesia.",category:"politik",significance:8,person_ids:["prabowo","khofifah"],tags:["pelantikan","kepala-daerah","pilkada-2024","gubernur","serentak"],source:"Kemendagri RI / Sekretariat Negara, Februari 2025"},{id:"t074",year:2025,month:3,day:20,title:"Revisi UU TNI Disahkan DPR — Kontroversi Dwifungsi",description:"DPR mengesahkan Revisi UU TNI yang memperluas jabatan sipil bagi perwira militer aktif. RUU disetujui di tengah demonstrasi besar mahasiswa di berbagai kota. Kritik keras: Indonesia dianggap mundur ke praktik Orde Baru dengan dwifungsi TNI.",category:"militer",significance:9,person_ids:["prabowo","puan"],tags:["uu-tni","dwifungsi","revisi","kontroversi","demonstrasi"],source:"DPR RI, Maret 2025"},{id:"t075",year:2025,month:3,day:1,title:"Efisiensi Anggaran — Pemotongan APBN Rp306 Triliun",description:"Pemerintah Prabowo memotong anggaran APBN 2025 sebesar Rp 306 triliun melalui Instruksi Presiden. Langkah efisiensi besar-besaran ini berdampak pada pemangkasan belanja kementerian, anggaran perjalanan dinas, dan proyek infrastruktur non-prioritas.",category:"ekonomi",significance:8,person_ids:["prabowo","sri_mulyani"],tags:["efisiensi","apbn","pemotongan","inpres","fiskal"],source:"Kemenkeu RI, Februari-Maret 2025"},{id:"t076",year:2025,month:4,day:1,title:"Tarif Trump — AS Kenakan Tarif 32% untuk Indonesia",description:"Pemerintah AS di bawah Trump mengumumkan tarif impor 32% untuk produk Indonesia dalam kebijakan 'Liberation Day'. Indonesia masuk daftar negara yang terkena tarif tinggi. Pemerintah Prabowo berupaya negosiasi untuk mendapatkan keringanan.",category:"internasional",significance:8,person_ids:["prabowo","sri_mulyani"],tags:["trump","tarif","perdagangan","as","proteksionisme"],source:"White House / Kemlu RI, April 2025"},{id:"t077",year:2023,month:10,day:19,title:"Koalisi Perubahan Daftarkan Anies-Muhaimin",description:"Koalisi Perubahan (NasDem, PKB, PKS) mendaftarkan Anies Baswedan-Muhaimin Iskandar sebagai paslon capres-cawapres ke KPU. Paslon Nomor 1 mengusung tema perubahan dan keadilan.",category:"pemilu",significance:8,person_ids:["anies","cakimin","surya_paloh"],tags:["anies","cak-imin","pilpres-2024","koalisi-perubahan","kpu"],source:"KPU RI, Oktober 2023"},{id:"t078",year:2023,month:10,day:25,title:"PDIP Daftarkan Ganjar-Mahfud",description:"PDIP mendaftarkan Ganjar Pranowo-Mahfud MD sebagai paslon capres-cawapres nomor 3. Mahfud MD mundur dari jabatan Menkopolhukam untuk maju Pilpres. PDIP memilih Ganjar meskipun Jokowi — kader PDIP — mendukung Prabowo.",category:"pemilu",significance:8,person_ids:["ganjar","megawati","jokowi"],tags:["ganjar","mahfud","pdip","pilpres-2024","kpu"],source:"KPU RI, Oktober 2023"},{id:"t079",year:2024,month:12,day:1,title:"Pelantikan Pimpinan KPK Baru 2024-2029",description:"Presiden Jokowi melantik pimpinan KPK periode 2024-2029: Nawawi Pomolango (Ketua), bersama empat wakil ketua lainnya. Pelantikan berlangsung di akhir era Jokowi, menandai regenerasi kepemimpinan KPK pasca era Firli Bahuri.",category:"hukum",significance:7,person_ids:["nawawi","jokowi"],tags:["kpk","pimpinan","nawawi","pelantikan","2024"],source:"KPK RI / Presiden RI, Desember 2024"},{id:"t080",year:2024,month:8,day:22,title:"Demo Kawal Putusan MK — 'Peringatan Darurat' Viral",description:"Ratusan ribu warga turun ke jalan di seluruh Indonesia memprotes manuver DPR yang hendak membatalkan putusan MK soal syarat pencalonan Pilkada. Simbol 'Peringatan Darurat' dan Garuda biru viral di media sosial. DPR akhirnya mundur.",category:"politik",significance:9,person_ids:["jokowi","puan","megawati"],tags:["demo","mk","peringatan-darurat","pilkada","dpr","2024"],source:"Berbagai media, Agustus 2024"}],i=[{id:"reformasi",label:"Era Reformasi",years:[1998,2004],color:"#ef4444"},{id:"sby1",label:"SBY Periode 1",years:[2004,2009],color:"#3b82f6"},{id:"sby2",label:"SBY Periode 2",years:[2009,2014],color:"#2563eb"},{id:"jokowi1",label:"Jokowi Periode 1",years:[2014,2019],color:"#f59e0b"},{id:"jokowi2",label:"Jokowi Periode 2",years:[2019,2024],color:"#d97706"},{id:"prabowo",label:"Era Prabowo",years:[2024,2029],color:"#8B0000"}],e={politik:{color:"#3b82f6",label:"Politik",emoji:"🏛️"},hukum:{color:"#ef4444",label:"Hukum",emoji:"⚖️"},ekonomi:{color:"#22c55e",label:"Ekonomi",emoji:"💰"},pemilu:{color:"#f59e0b",label:"Pemilu",emoji:"🗳️"},bencana:{color:"#6b7280",label:"Bencana",emoji:"🚨"},militer:{color:"#8b5cf6",label:"Militer",emoji:"⚔️"},internasional:{color:"#06b6d4",label:"Internasional",emoji:"🌐"}};export{e as C,i as E,a as T};
